/* ---------- section: Stats (gauge + bar chart) ---------- */
function GaugeCard() {
  const progress = 0.89;
  const cx = 100;
  const cy = 100;
  const r = 80;
  const startDeg = 180;
  const endDeg = 0;
  const path = `M ${cx - r} ${cy} A ${r} ${r} 0 0 1 ${cx + r} ${cy}`;
  const pathLength = Math.PI * r;

  const thetaDeg = startDeg - (startDeg - endDeg) * progress;
  const thetaRad = (thetaDeg * Math.PI) / 180;
  const dotX = cx + r * Math.cos(thetaRad);
  const dotY = cy - r * Math.sin(thetaRad);

  return (
    <div className="stat-card gauge-card">
      <svg viewBox="0 0 200 110" className="gauge-svg" aria-hidden="true">
        <path
          d={path}
          fill="none"
          stroke="#e7e9f7"
          strokeWidth="14"
          strokeLinecap="round"
        />
        <path
          d={path}
          fill="none"
          stroke="#de5cc7"
          strokeWidth="14"
          strokeLinecap="round"
          strokeDasharray={`${pathLength * progress} ${pathLength}`}
        />
        <circle cx={dotX} cy={dotY} r="11" fill="#fff" />
        <circle cx={dotX} cy={dotY} r="8.5" fill="#d118ae" />
      </svg>
      <p className="gauge-number">89%</p>
      <p className="gauge-caption">
        Thinks sharing music directly would be useful
      </p>
    </div>
  );
}

